'use client';

import { useColleges } from '@/hooks/useColleges';
import CollegeCard from '@/components/college/CollegeCard';
import { SearchSection } from '@/components/college/SearchSection';
import { LoadingSkeleton, EmptyState } from '@/components/college/States';
import { Button } from '@/components/ui/button';
import { GraduationCap, Sparkles, BookOpen, Users, AlertCircle } from 'lucide-react';

export default function Home() {
  const {
    colleges,
    loading,
    error,
    search,
    setSearch,
    stream,
    setStream,
    sortBy,
    setSortBy,
    loadMore,
    hasMore,
    totalCount,
    retry,
  } = useColleges();

  const clearFilters = () => {
    setSearch('');
    setStream('All');
    setSortBy('rating');
  };

  return (
    <main id="main-content" className="min-h-screen bg-[#F8FAFC]">
      <section className="relative overflow-hidden bg-blue-600 px-4 pb-32 pt-20 text-white sm:px-6 sm:pb-40 sm:pt-24 md:pb-48">
        <div className="absolute inset-0 z-0" aria-hidden>
          <div className="absolute right-[-10%] top-[-10%] h-[50%] w-[50%] rounded-full bg-blue-500 opacity-20 blur-[120px]" />
          <div className="absolute bottom-[-10%] left-[-10%] h-[50%] w-[50%] rounded-full bg-blue-400 opacity-20 blur-[120px]" />
        </div>

        <div className="relative z-10 mx-auto max-w-7xl text-center">
          <div className="mb-6 inline-flex items-center gap-2 rounded-full border border-white/20 bg-white/10 px-3 py-1.5 backdrop-blur-md sm:mb-8 sm:px-4 sm:py-2">
            <Sparkles className="h-4 w-4 text-blue-200" aria-hidden />
            <span className="text-[10px] font-bold uppercase tracking-widest text-blue-100 sm:text-xs">
              India&apos;s Leading Discovery Platform
            </span>
          </div>

          <h1 className="mb-4 text-3xl font-extrabold tracking-tight sm:mb-6 sm:text-5xl md:text-7xl">
            Find Your Dream <br />
            <span className="bg-gradient-to-r from-blue-200 to-white bg-clip-text text-transparent">
              College with EduTrack
            </span>
          </h1>

          <p className="mx-auto mb-8 max-w-2xl text-base text-blue-100/80 sm:mb-12 sm:text-lg md:text-xl">
            Explore 1000+ top-rated institutions. Compare fees, placements, and reviews to make the best choice for your future.
          </p>

          <div className="flex flex-wrap justify-center gap-4 font-medium text-blue-50/60 sm:gap-8">
            <div className="flex items-center gap-2">
              <BookOpen className="h-5 w-5 text-blue-300" aria-hidden />
              <span className="text-sm sm:text-base">800+ Courses</span>
            </div>
            <div className="flex items-center gap-2">
              <Users className="h-5 w-5 text-blue-300" aria-hidden />
              <span className="text-sm sm:text-base">10L+ Students</span>
            </div>
            <div className="flex items-center gap-2">
              <GraduationCap className="h-5 w-5 text-blue-300" aria-hidden />
              <span className="text-sm sm:text-base">Top NIRF Colleges</span>
            </div>
          </div>
        </div>
      </section>

      <div className="mx-auto max-w-7xl px-4 pb-16 sm:px-6 sm:pb-24">
        <SearchSection
          search={search}
          setSearch={setSearch}
          stream={stream}
          setStream={setStream}
          sortBy={sortBy}
          setSortBy={setSortBy}
        />

        <div className="mb-6 flex flex-col gap-3 sm:mb-8 sm:flex-row sm:items-center sm:justify-between">
          <h2 className="text-xl font-bold text-gray-900 sm:text-2xl">
            {loading ? 'Finding Colleges...' : `Showing ${totalCount} Result${totalCount !== 1 ? 's' : ''}`}
          </h2>
          <Button variant="ghost" size="sm" onClick={clearFilters} className="self-start sm:self-auto">
            Reset All
          </Button>
        </div>

        {error ? (
          <div
            role="alert"
            className="flex flex-col items-center rounded-2xl border border-red-100 bg-red-50 px-6 py-12 text-center"
          >
            <AlertCircle className="mb-4 h-10 w-10 text-red-500" aria-hidden />
            <p className="mb-4 font-semibold text-red-800">{error}</p>
            <Button onClick={retry} variant="outline">
              Try Again
            </Button>
          </div>
        ) : loading && colleges.length === 0 ? (
          <LoadingSkeleton />
        ) : colleges.length > 0 ? (
          <>
            <div
              className="grid grid-cols-1 gap-6 sm:grid-cols-2 sm:gap-8 lg:grid-cols-3 xl:grid-cols-4"
              aria-live="polite"
              aria-busy={loading}
            >
              {colleges.map((college) => (
                <CollegeCard key={college.id} college={college} />
              ))}
            </div>

            {hasMore && (
              <div className="mt-12 text-center sm:mt-16">
                <Button
                  onClick={loadMore}
                  variant="outline"
                  size="lg"
                  className="rounded-full border-2 px-8 py-5 text-base font-bold shadow-xl transition-all hover:border-blue-600 hover:bg-blue-600 hover:text-white sm:px-12 sm:py-6"
                  aria-label="Load more colleges"
                >
                  Explore More Colleges
                </Button>
              </div>
            )}
          </>
        ) : (
          <EmptyState onClear={clearFilters} />
        )}
      </div>
    </main>
  );
}
